var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"제 1포문! 탄약 일발 장전!","JPN":"第1砲門！　弾薬1発装填！","ENG":"Cannon 1! Loading!","TWN":"第1炮門！裝填彈藥一發！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"......발사!","JPN":"……発射！","ENG":"Fire!","TWN":"……發射！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"흡!","JPN":"ふぅっ！","ENG":"Hmpf!","TWN":"喝！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"뭐였지? 불발인가?","JPN":"何だ？　不発か？","ENG":"What was that? Was it a dud?","TWN":"怎麼了？是啞彈嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"그런 게 아냐. 대령님의 주먹에 신관이 통째로 녹았어.","JPN":"そんなんじゃない。大佐の拳で信管が丸ごと溶けてしまったんだよ。","ENG":"That's not it. The Colonel's punch blew out the fuse.","TWN":"不是吧，上校的拳頭居然把引信整個融化掉了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이걸론 부족해. 뭔가 좀 더 강한 게......","JPN":"これじゃ足りないな。なんかもっと強いのが……","ENG":"This isn't enough. I need something stronger...","TWN":"這還不夠。有沒有更強的……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"콜록, 콜록!","JPN":"ゲホ、ゲホ！","ENG":"*Cough, cough*","TWN":"咳咳，咳咳！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으, 타르 끓는 냄새. 저번엔 대전차 로켓에 주먹질을 하더니 이번엔 함포 미사일이야?","JPN":"うう、タール臭い。この前は対戦車ロケットを殴り付けてたのに、今回は艦砲ミサイルなの？","ENG":"Ugh, I can smell the tar boiling. Last time you were throwing punches at antitank rockets. This time, it's naval guns?","TWN":"呃，有股焦油沸騰的味道。上次是對反坦克炮出拳，這次輪到艦炮導彈了嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이왕이면 플라즈마 입자포도 쏴줄까? 그것도 맞받아 쳐볼래?","JPN":"ついでに、プラズマ粒子砲でも打ってあげようか？　それも迎え撃ってみる？","ENG":"Would you like me to shoot you a plasma particle cannon as well? See if you can hit that back?","TWN":"既然如此，給你來一發等離子炮怎麼樣呢？你就接接看啊？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"입자포라...... 나쁘지 않은 생각인걸? 훈련에 도움이 되겠어.","JPN":"プラズマ粒子砲か……それも悪くないな。訓練に役立ちそうだ。","ENG":"Particle cannon, huh... Actually, that's not a bad idea. It could help with the training.","TWN":"等離子炮……不錯的主意吧？肯定會對訓練有所幫助。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"요즘 대체 왜 그래? 설마 그 날의 일을 아직도 마음에 담아두고 있는 거야?","JPN":"最近いったいどうしたの？　まさか、あの日のことをまだ引きずってるの？","ENG":"What's gotten into you lately? You're not still hung up on what happened that day, are you?","TWN":"你最近到底怎麼回事？該不會還在想那天的事吧？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"네가 상대했던 건 무한하게 재생하는 규격 외의 괴물이었다고!","JPN":"あなたが相手にしたのは、無限に再生する規格外の怪物だったのよ！","ENG":"You were up against a monster that could literally keep regenerating!","TWN":"你當時的對手可是個會無限再生的超規格怪物啊！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그런 녀석을 상대로 자존심이 상하면 어쩌겠다는 거야?","JPN":"そんな奴を相手にプライドを傷つけられてどうするの？","ENG":"There's no shame in struggling with something like that!","TWN":"竟然被那種東西傷了自尊心，你到底是怎樣啊？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 부수지 못할 벽은 아니었지.","JPN":"しかし、壊せないほどの壁ではなかった。","ENG":"But it wasn't completely invulnerable.","TWN":"但那也不是完全無法打倒的對手。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"언젠가는 그보다 더 한 적이 나타날 수도 있어.","JPN":"いつかあれよりもっとやばい敵が現れるかもしれない。","ENG":"One day, something much more formidable could show up.","TWN":"總有一天會出現更厲害的敵人。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이 정도의 적도 상대하지 못한다면 진짜 위기에는 대응할 수 없으니까.","JPN":"この程度の敵も潰せないのなら、本当の危機が迫ったときには対応できないからな。","ENG":"If I can't fight enemies at this level, I won't be able to respond to a real crisis.","TWN":"如果連這種敵人都對付不了，就無法應對真正的危機。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};